/**
 * Mock data for the Data › Refunds record-explorer page.
 *
 * Ported from /Users/mac/Downloads/MAGELLAN UX/Data/magellan-data-refunds.html
 * Currency converted ฿ → $ (same digits, $ symbol) per the Magellan currency rule.
 *
 * A refund is a distinct record: an amount (often partial), a reason, a gateway
 * path (automatic vs manual transfer), who initiated it, a time-to-refund, and a
 * link back to the original order. The record is NEUTRAL — whether the refund
 * *rate* is a problem, and what to do about it, is a verdict that routes to a
 * Room (Operations / Customers / Finance).
 *
 * The template builds 46 deterministic records with a seeded RNG (mulberry32,
 * seed 73); we reproduce that generator verbatim so the rows are stable across
 * renders, then freeze the array (sorted newest-first) and expose typed column /
 * filter / calendar metadata plus the pure helpers the page reuses.
 */

/* ─────────────────────────── Types ─────────────────────────── */

export type RefundStatus = "completed" | "processing" | "requested";
export type RefundType = "full" | "partial";
export type GatewayType = "auto" | "manual";
export type ReasonRoom = "Operations" | "Customers" | "Finance";

export interface RefundRecord {
  id: string;
  orderId: string;
  /** ISO date (YYYY-MM-DD) of the refund — used for date-range filtering */
  date: string;
  /** ms epoch of the refund request, for stable date sort */
  ts: number;
  time: string;
  customer: string;
  product: string;
  orderTotal: number;
  amount: number;
  refundType: RefundType;
  reason: string;
  reasonKey: string;
  reasonRoom: ReasonRoom;
  payMethod: string;
  processor: string;
  gwType: GatewayType;
  status: RefundStatus;
  ttrHours: number;
  ttrLabel: string;
  initiator: string;
  /** timeline steps: [label, timestamp] */
  tl: Array<[string, string]>;
}

export type ColumnKey =
  | "id"
  | "customer"
  | "reason"
  | "refundType"
  | "amount"
  | "gwType"
  | "ttr"
  | "status"
  | "orderId";

export interface ColumnDef {
  k: ColumnKey;
  label: string;
  on: boolean;
  num?: boolean;
  fixed?: boolean;
}

export type FilterKey = "reasonKey" | "gwType" | "status";

/* ─────────────────────────── Seeded RNG (mulberry32, seed 73) ─────────────────────────── */

function mulberry32(a: number) {
  return function () {
    a |= 0;
    a = (a + 0x6d2b79f5) | 0;
    let t = Math.imul(a ^ (a >>> 15), 1 | a);
    t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t;
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  };
}
const rng = mulberry32(73);
const pick = <T>(arr: readonly T[]): T => arr[Math.floor(rng() * arr.length)];
const between = (a: number, b: number) => a + Math.floor(rng() * (b - a + 1));

