/* products that can be refunded — [name, price] (USD, same digits as template ฿) */
const RPRODUCTS: ReadonlyArray<[string, number]> = [
  ["Signature Rose Box · Large", 2890],
  ["Grand Anniversary Arrangement", 6900],
  ["Devil’s Chocolate Cake · Large", 2990],
  ["Swedish Princess Cake · Medium", 2190],
  ["Luxe Orchid Display", 4490],
  ["Hydrangea Arrangement", 2390],
  ["Banana Tiramisu · Large", 2290],
  ["Premium Gift Basket", 2490],
  ["Carnation Posy", 1812],
  ["Orange Hazelnut Dacquoise · Medium", 2490],
];

const TODAY = new Date(2026, 4, 26);

function fmt(d: Date): string {
  return d
    .toLocaleString("en-GB", { day: "numeric", month: "short", hour: "2-digit", minute: "2-digit" })
    .replace(",", "");
}

function genRefund(i: number): RefundRecord {
  const [reasonName, reasonKey, reasonRoom] = pick(REASONS);
  const [payMethod, processor, gwType] = pick(GATEWAYS);
  const prod = pick(RPRODUCTS);
  const orderTotal =
    prod[1] +
    (rng() < 0.5 ? between(0, 2) * pick(RPRODUCTS)[1] : 0) +
    (rng() < 0.4 ? between(60, 180) : 0);

  // partial vs full refund
  const isFull = rng() < 0.46;
  const amount = isFull ? orderTotal : Math.round((orderTotal * (0.3 + rng() * 0.5)) / 10) * 10;
  const refundType: RefundType = isFull ? "full" : "partial";

  // status of the refund itself
  let status: RefundStatus;
  const sr = rng();
  if (sr < 0.72) status = "completed";
  else if (sr < 0.9) status = "processing";
  else status = "requested";

  // time to refund (hours) — auto is fast, manual slower
  const ttrHours = gwType === "auto" ? 0.2 + rng() * 6 : 8 + rng() * 60;

  // dates — anchored to 26 May 2026
  const daysAgo = between(0, 44);
  const dt = new Date(2026, 4, 26);
  dt.setDate(dt.getDate() - daysAgo);
  dt.setHours(between(8, 21), between(0, 59));
  const orderId = "#" + (64000 - between(20, 900));
  const initiator = rng() < 0.62 ? "Customer request" : "Staff (Alice)";

  // timeline
  const tl: Array<[string, string]> = [];
  let c = new Date(dt);
  tl.push(["Refund requested", fmt(c)]);
  if (status !== "requested") {
    c = new Date(c.getTime() + between(20, 180) * 60000);
    tl.push(["Approved", fmt(c)]);
  }
  if (status === "completed") {
    c = new Date(c.getTime() + ttrHours * 3600000);
    tl.push([gwType === "auto" ? `Auto-refunded · ${processor}` : "Manual transfer sent", fmt(c)]);
  }

  return {
    id: "R-" + (4400 + i),
    orderId,
    date: dt.toISOString().slice(0, 10),
    ts: dt.getTime(),
    time: dt.toLocaleString("en-GB", { hour: "2-digit", minute: "2-digit" }),
    customer: `${pick(FIRST)} ${pick(LAST)}`,
    product: prod[0],
    orderTotal,
    amount,
    refundType,
    reason: reasonName,
    reasonKey,
    reasonRoom,
    payMethod,
    processor,
    gwType,
    status,
    ttrHours,
    ttrLabel:
      gwType === "auto"
        ? ttrHours < 1
          ? `${Math.round(ttrHours * 60)} min`
          : `${ttrHours.toFixed(1)} hr`
        : `${ttrHours.toFixed(0)} hr`,
    initiator,
    tl,
  };
}

/* The 46 deterministic refund records, newest first. */
export const REFUNDS: RefundRecord[] = Array.from({ length: 46 }, (_, i) =>
  genRefund(i + 1),
).sort((a, b) => b.ts - a.ts);

