/* ─────────────────────────── Helpers (pure, reused by the page) ─────────────────────────── */

export function statusLabel(s: string): string {
  return s.charAt(0).toUpperCase() + s.slice(1);
}

export function usd(n: number): string {
  return "$" + Math.round(n).toLocaleString();
}

/** Where the verdict lives — neutral record, the fix routes to a Room. */
export function refundRoute(o: RefundRecord): string {
  const map: Record<ReasonRoom, string> = {
    Operations: `Fulfillment-driven refund (${o.reason.toLowerCase()}). If this reason is trending, the fix is in dispatch and quality — not here.`,
    Customers: `Customer-choice refund (${o.reason.toLowerCase()}). Pattern and win-back handling live with the customer relationship.`,
    Finance: `Process refund (${o.reason.toLowerCase()}). Reconciliation and gateway-fee impact are a Finance matter.`,
  };
  return map[o.reasonRoom];
}

/** Count distinct values for a filterable column, sorted by frequency. */
export function uniqueVals(key: FilterKey): Array<[string, number]> {
  const m: Record<string, number> = {};
  for (const o of REFUNDS) {
    const v = o[key];
    m[v] = (m[v] || 0) + 1;
  }
  return Object.entries(m).sort((a, b) => b[1] - a[1]);
}

/** Label a filter value for display in the checklist popover. */
export function filterValLabel(key: FilterKey, v: string): string {
  if (key === "reasonKey") return REASON_LABEL[v] ?? v;
  if (key === "gwType") return GW_META[v as GatewayType]?.[0] ?? v;
  return statusLabel(v);
}

/**
 * 30-day refunds-per-day buckets ending 26 May 2026 (for the trend sparkline),
 * recomputed live from the filtered set.
 */
export function refundsPerDay(rows: RefundRecord[]): number[] {
  const buckets: Array<{ iso: string; c: number }> = [];
  for (let i = 29; i >= 0; i--) {
    const d = new Date(TODAY);
    d.setDate(TODAY.getDate() - i);
    buckets.push({ iso: d.toISOString().slice(0, 10), c: 0 });
  }
  const idx: Record<string, number> = {};
  buckets.forEach((b, i) => (idx[b.iso] = i));
  for (const o of rows) {
    if (o.date in idx) buckets[idx[o.date]].c += 1;
  }
  return buckets.map((b) => b.c);
}
